const response = $.steps.exaSearch.response || {};
const data = response.data || response;
const results = data.results || [];

let context = '';
const sources = [];

results.slice(0, 10).forEach((r, i) => {
  const title = r.title || 'Source ' + (i + 1);
  const url = r.url || '';
  const text = (r.text || r.snippet || '').slice(0, 2000);
  context += '=== SOURCE ' + (i + 1) + ' ===\n';
  context += 'Title: ' + title + '\n';
  context += 'URL: ' + url + '\n';
  context += 'Content:\n' + text + '\n\n';
  sources.push({ title, url });
});

return { context, sources, resultCount: results.length };

const question = $.input.question;
const ctx = $.steps.compileContext.output;

let prompt = 'You are a knowledgeable assistant that answers questions using retrieved context. Use ONLY the provided sources to answer. If the sources do not contain enough information, say so clearly.

';
prompt += 'QUESTION: ' + question + '

';
prompt += 'RETRIEVED CONTEXT (' + ctx.resultCount + ' sources):
' + ctx.context + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Answer the question thoroughly using the provided sources
';
prompt += '- Cite source numbers in your answer (e.g., [Source 1])
';
prompt += '- If sources conflict, note the discrepancy
';
prompt += '- Be concise but comprehensive (200-400 words)

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "answer": "your detailed answer with source citations",
';
prompt += '  "confidence": "high|medium|low",
';
prompt += '  "sourcesUsed": [1, 2, 3],
';
prompt += '  "keyPoints": ["point1", "point2"],
';
prompt += '  "followUpQuestions": ["question1"]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'unknown', sourcesUsed: [], keyPoints: [], followUpQuestions: [] }; }

const ai = $.steps.parseAI.output;
const ctx = $.steps.compileContext.output;
const question = $.input.question;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'RAG Knowledge Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Sources Retrieved:*\n' + ctx.resultCount },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') }
] });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer:*\n' + answerText } });

if (ai.keyPoints && ai.keyPoints.length > 0) {
  let kpText = '*Key Points:*\n';
  ai.keyPoints.slice(0, 5).forEach((kp, i) => { kpText += (i + 1) + '. ' + kp + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText.slice(0, 1800) } });
}

if (ctx.sources && ctx.sources.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources:*\n';
  ctx.sources.slice(0, 5).forEach((s, i) => {
    srcText += (i + 1) + '. <' + s.url + '|' + (s.title || 'Source') + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}

if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  let fuText = '*Follow-up Questions:*\n';
  ai.followUpQuestions.slice(0, 3).forEach((q, i) => { fuText += '- ' + q + '\n'; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: fuText.slice(0, 1800) }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI (RAG)' }] });

const fallbackText = 'RAG Answer: ' + question.slice(0, 50) + ' - ' + (ai.answer || '').slice(0, 100);
return { blocks, fallbackText };
